-- FSI_DEMO_DB.WEALTH_MANAGEMENT.CLIENT_GOALS

CREATE OR REPLACE TABLE FSI_DEMO_DB.WEALTH_MANAGEMENT.CLIENT_GOALS (

    GOAL_ID VARCHAR(20) NOT NULL,
    CLIENT_ID VARCHAR(20),
    GOAL_NAME VARCHAR(100),
    GOAL_TYPE VARCHAR(50),
    TARGET_AMOUNT NUMBER(18,2),
    CURRENT_AMOUNT NUMBER(18,2),
    TARGET_DATE DATE,
    PRIORITY NUMBER(2,0),
    STATUS VARCHAR(30),
    FUNDING_STRATEGY VARCHAR(200),
    MONTHLY_CONTRIBUTION NUMBER(12,2),
    PROGRESS_PCT NUMBER(5,4),
    RISK_LEVEL VARCHAR(30),
    NOTES VARCHAR(16777216),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (GOAL_ID)

);




